-- ═══ 9. Set up manager relationships ═══

-- ═══ 10. Assign work schedules ═══
SELECT e.id, st.id, COALESCE(e.hire_date, CURRENT_DATE)
FROM employees e
JOIN companies c ON c.id = e.company_id
JOIN shift_templates st ON st.company_id = c.id AND st.name = '09:00-18:00'
WHERE e.id NOT IN (SELECT ws.employee_id FROM work_schedules ws)
AND e.id NOT IN ('11655ff2-5e7e-4e80-8a26-e910aa257192','79cfbb9a-cf6c-45d7-bed9-a630e4cee21b');

-- ═══ 11. Assign allowed locations (branch) ═══
SELECT gen_random_uuid(), e.id, e.branch_id
FROM employees e
WHERE e.branch_id IS NOT NULL
AND e.id NOT IN ('11655ff2-5e7e-4e80-8a26-e910aa257192','79cfbb9a-cf6c-45d7-bed9-a630e4cee21b')
AND NOT EXISTS (SELECT 1 FROM employee_allowed_locations eal WHERE eal.employee_id = e.id);

-- ═══ 12. Insert leave types per company ═══

-- ═══ 13. Create leave balances for 2026 ═══
SELECT gen_random_uuid(), e.id, lt.id, 2026, COALESCE(lt.days_per_year, 0), 0, 0, 0, COALESCE(lt.days_per_year, 0)
FROM employees e
JOIN leave_types lt ON lt.company_id = e.company_id AND lt.is_active = true
WHERE NOT EXISTS (
  SELECT 1 FROM leave_balances lb WHERE lb.employee_id = e.id AND lb.leave_type_id = lt.id AND lb.year = 2026
);

-- ═══ 14. Create users for new employees ═══
-- Each employee gets a 'employee' role user
SELECT gen_random_uuid(), e.id, 'employee'::user_role, e.company_id, true
FROM employees e
WHERE e.id NOT IN ('11655ff2-5e7e-4e80-8a26-e910aa257192','79cfbb9a-cf6c-45d7-bed9-a630e4cee21b')
AND NOT EXISTS (SELECT 1 FROM users u WHERE u.employee_id = e.id);

COMMIT;

